questions.prompt:
This shell helper estimates a token count for its argument. It is called throughout a pipeline, sometimes with an empty string. Name the most serious defect and why.

estimate_tokens() {
  local text="$1"
  if [[ -z "$text" ]]; then
    text=$(cat)          # no argument given: read from stdin
  fi
  echo $(( ${#text} / 4 ))
}

# usage, e.g.:  n=$(estimate_tokens "$chunk")   # $chunk can be ""
